/**
 * Notification log model for tracking sent notifications.
 *
 * Captures: recipient, channel, type, timestamp, and delivery status
 * for every notification that passes through the notification system.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

export type DeliveryStatus = 'sent' | 'delivered' | 'failed';

export interface NotificationLog {
  /** Unique log entry ID */
  id: string;
  /** The notification ID from NotificationService */
  notificationId: string;
  /** Recipient identifier (email, user ID, webhook URL, etc.) */
  recipient: string;
  /** Delivery channel used */
  channel: NotificationChannel;
  /** Notification category */
  type: NotificationType;
  /** Subject/title of the notification */
  subject: string;
  /** Delivery status */
  status: DeliveryStatus;
  /** Error message if delivery failed */
  error?: string;
  /** When the notification was sent */
  sentAt: Date;
  /** When the log entry was created */
  loggedAt: Date;
}

export interface NotificationHistoryQuery {
  /** Filter by recipient */
  recipient?: string;
  /** Filter by notification type */
  type?: NotificationType;
  /** Filter by delivery channel */
  channel?: NotificationChannel;
  /** Filter by delivery status */
  status?: DeliveryStatus;
  /** Start of date range (inclusive) */
  from?: Date;
  /** End of date range (inclusive) */
  to?: Date;
}

/**
 * Notification history service — logs and queries sent notifications.
 *
 * Stores notification log entries in memory. Integrated into NotificationService
 * as an optional dependency to log every notification after it's sent.
 *
 * Provides query methods for filtering by recipient, type, channel, status,
 * and date range.
 */

import type {
  NotificationLog,
  NotificationHistoryQuery,
  DeliveryStatus,
} from '../models/notification-log.js';
import type {
  NotificationChannel,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `log-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');
  private logs: NotificationLog[] = [];

  /**
   * Record a notification in the history log.
   */
  log(entry: {
    notificationId: string;
    recipient: string;
    channel: NotificationChannel;
    type: NotificationType;
    subject: string;
    status: DeliveryStatus;
    error?: string;
    sentAt: Date;
  }): NotificationLog {
    const logEntry: NotificationLog = {
      id: generateLogId(),
      notificationId: entry.notificationId,
      recipient: entry.recipient,
      channel: entry.channel,
      type: entry.type,
      subject: entry.subject,
      status: entry.status,
      error: entry.error,
      sentAt: entry.sentAt,
      loggedAt: new Date(),
    };

    this.logs.push(logEntry);
    this.logger.info(
      `Logged notification ${entry.notificationId}: ${entry.type} via ${entry.channel} -> ${entry.status}`,
    );

    return { ...logEntry };
  }

  /**
   * Query notification history with optional filters.
   * All filters are combined with AND logic.
   */
  query(filter: NotificationHistoryQuery = {}): NotificationLog[] {
    let results = this.logs;

    if (filter.recipient !== undefined) {
      results = results.filter((l) => l.recipient === filter.recipient);
    }
    if (filter.type !== undefined) {
      results = results.filter((l) => l.type === filter.type);
    }
    if (filter.channel !== undefined) {
      results = results.filter((l) => l.channel === filter.channel);
    }
    if (filter.status !== undefined) {
      results = results.filter((l) => l.status === filter.status);
    }
    if (filter.from !== undefined) {
      const from = filter.from;
      results = results.filter((l) => l.sentAt >= from);
    }
    if (filter.to !== undefined) {
      const to = filter.to;
      results = results.filter((l) => l.sentAt <= to);
    }

    return results.map((l) => ({ ...l }));
  }

  /**
   * Get all log entries for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.query({ recipient });
  }

  /**
   * Get all log entries of a specific notification type.
   */
  getByType(type: NotificationType): NotificationLog[] {
    return this.query({ type });
  }

  /**
   * Get all log entries within a date range.
   */
  getByDateRange(from: Date, to: Date): NotificationLog[] {
    return this.query({ from, to });
  }

  /**
   * Get the total count of logged notifications.
   */
  getCount(): number {
    return this.logs.length;
  }

  /**
   * Clear all log entries (useful for testing).
   */
  clear(): void {
    this.logs = [];
  }
}

