import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationLog } from '../../src/models/notification-log.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../../src/events/event-types.js';

function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date('2026-01-15T10:00:00Z'),
      updatedAt: new Date('2026-01-15T10:00:00Z'),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2026-01-15T10:00:00Z'),
    ...overrides,
  };
}

function makeStatusChangedEvent(overrides?: Partial<OrderStatusChangedEvent>): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date('2026-01-15T12:00:00Z'),
    ...overrides,
  };
}

function makeUserCreatedEvent(overrides?: Partial<UserCreatedEvent>): UserCreatedEvent {
  return {
    type: 'user:created',
    user: {
      id: 'user-2',
      name: 'Bob',
      email: 'bob@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2026-01-15T11:00:00Z'),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    historyService = new NotificationHistoryService();
    resetLogIdCounter();
  });

  describe('log()', () => {
    it('should create a log entry with all fields', () => {
      const entry = historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order Confirmation: order-1',
        status: 'delivered',
        sentAt: new Date('2026-01-15T10:00:00Z'),
      });

      expect(entry.id).toBe('log-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order_confirmation');
      expect(entry.subject).toBe('Order Confirmation: order-1');
      expect(entry.status).toBe('delivered');
      expect(entry.sentAt).toEqual(new Date('2026-01-15T10:00:00Z'));
      expect(entry.loggedAt).toBeInstanceOf(Date);
    });

    it('should generate sequential log IDs', () => {
      const e1 = historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome',
        status: 'sent',
        sentAt: new Date(),
      });
      const e2 = historyService.log({
        notificationId: 'notif-0002',
        recipient: 'bob@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome',
        status: 'sent',
        sentAt: new Date(),
      });

      expect(e1.id).toBe('log-0001');
      expect(e2.id).toBe('log-0002');
    });

    it('should record error on failed delivery', () => {
      const entry = historyService.log({
        notificationId: 'notif-0001',
        recipient: 'bad@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome',
        status: 'failed',
        error: 'Invalid recipient',
        sentAt: new Date(),
      });

      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('Invalid recipient');
    });

    it('should return a copy of the log entry', () => {
      const entry = historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome',
        status: 'sent',
        sentAt: new Date(),
      });

      entry.recipient = 'mutated@example.com';
      const queried = historyService.query({ recipient: 'alice@example.com' });
      expect(queried).toHaveLength(1);
    });
  });

  describe('query()', () => {
    beforeEach(() => {
      historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order Confirmation',
        status: 'delivered',
        sentAt: new Date('2026-01-15T10:00:00Z'),
      });
      historyService.log({
        notificationId: 'notif-0002',
        recipient: 'bob@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome',
        status: 'delivered',
        sentAt: new Date('2026-01-15T11:00:00Z'),
      });
      historyService.log({
        notificationId: 'notif-0003',
        recipient: 'alice@example.com',
        channel: 'webhook',
        type: 'order_status_update',
        subject: 'Status Update',
        status: 'failed',
        error: 'Timeout',
        sentAt: new Date('2026-01-15T12:00:00Z'),
      });
    });

    it('should return all entries when no filter is given', () => {
      expect(historyService.query()).toHaveLength(3);
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      expect(results.every((r) => r.recipient === 'alice@example.com')).toBe(true);
    });

    it('should filter by type', () => {
      const results = historyService.query({ type: 'welcome' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('welcome');
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.status).toBe('failed');
    });

    it('should filter by date range', () => {
      const results = historyService.query({
        from: new Date('2026-01-15T10:30:00Z'),
        to: new Date('2026-01-15T11:30:00Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should combine multiple filters with AND logic', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        status: 'delivered',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order_confirmation');
    });

    it('should return empty array when no matches', () => {
      expect(historyService.query({ recipient: 'nobody@example.com' })).toHaveLength(0);
    });

    it('should return copies that do not affect internal state', () => {
      const results = historyService.query();
      results[0]!.recipient = 'mutated@example.com';
      expect(historyService.query()[0]?.recipient).toBe('alice@example.com');
    });
  });

  describe('convenience query methods', () => {
    beforeEach(() => {
      historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order_confirmation',
        subject: 'Order Confirmation',
        status: 'delivered',
        sentAt: new Date('2026-01-15T10:00:00Z'),
      });
      historyService.log({
        notificationId: 'notif-0002',
        recipient: 'bob@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome',
        status: 'delivered',
        sentAt: new Date('2026-01-16T10:00:00Z'),
      });
    });

    it('getByRecipient should return entries for that recipient', () => {
      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
    });

    it('getByType should return entries of that type', () => {
      expect(historyService.getByType('welcome')).toHaveLength(1);
    });

    it('getByDateRange should return entries within the range', () => {
      const results = historyService.getByDateRange(
        new Date('2026-01-16T00:00:00Z'),
        new Date('2026-01-16T23:59:59Z'),
      );
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });
  });

  describe('getCount()', () => {
    it('should return 0 initially', () => {
      expect(historyService.getCount()).toBe(0);
    });

    it('should return correct count after logging', () => {
      historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome',
        status: 'sent',
        sentAt: new Date(),
      });
      expect(historyService.getCount()).toBe(1);
    });
  });

  describe('clear()', () => {
    it('should remove all log entries', () => {
      historyService.log({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'welcome',
        subject: 'Welcome',
        status: 'sent',
        sentAt: new Date(),
      });
      historyService.clear();
      expect(historyService.getCount()).toBe(0);
      expect(historyService.query()).toHaveLength(0);
    });
  });
});

describe('NotificationService + NotificationHistoryService integration', () => {
  let eventBus: EventBus;
  let historyService: NotificationHistoryService;
  let notificationService: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    historyService = new NotificationHistoryService();
    notificationService = new NotificationService(eventBus, undefined, historyService);
    resetNotificationIdCounter();
    resetLogIdCounter();
  });

  it('should log notification when event is emitted', async () => {
    await eventBus.emit(makeOrderCreatedEvent());

    const logs = historyService.query();
    expect(logs).toHaveLength(1);
    expect(logs[0]?.notificationId).toBe('notif-0001');
    expect(logs[0]?.recipient).toBe('alice@example.com');
    expect(logs[0]?.channel).toBe('email');
    expect(logs[0]?.type).toBe('order_confirmation');
    expect(logs[0]?.status).toBe('sent');
  });

  it('should log with delivered status when adapter succeeds', async () => {
    const adapter = new EmailNotificationAdapter({ from: 'noreply@test.com' });
    notificationService.registerAdapter(adapter);

    await eventBus.emit(makeOrderCreatedEvent());

    const logs = historyService.query();
    expect(logs).toHaveLength(1);
    expect(logs[0]?.status).toBe('delivered');
  });

  it('should log multiple notifications from different events', async () => {
    await eventBus.emit(makeOrderCreatedEvent());
    await eventBus.emit(makeUserCreatedEvent());
    await eventBus.emit(makeStatusChangedEvent());

    expect(historyService.getCount()).toBe(3);

    const orderLogs = historyService.getByType('order_confirmation');
    expect(orderLogs).toHaveLength(1);

    const welcomeLogs = historyService.getByType('welcome');
    expect(welcomeLogs).toHaveLength(1);

    const statusLogs = historyService.getByType('order_status_update');
    expect(statusLogs).toHaveLength(1);
  });

  it('should not log when notification is suppressed by preferences', async () => {
    const { PreferencesService } = await import('../../src/services/preferences.service.js');
    const prefs = new PreferencesService();

    prefs.updatePreferences('user-1', {
      email: { enabled: false, categories: [], frequency: 'immediate' },
    });

    const serviceWithPrefs = new NotificationService(eventBus, prefs, historyService);
    // Need a fresh eventBus since the old service already subscribed
    const freshBus = new EventBus();
    const freshService = new NotificationService(freshBus, prefs, historyService);

    historyService.clear();

    await freshBus.emit(makeOrderCreatedEvent());

    expect(historyService.getCount()).toBe(0);
  });

  it('should work without history service (backward compatibility)', async () => {
    const serviceWithoutHistory = new NotificationService(eventBus);

    // Should not throw
    await eventBus.emit(makeUserCreatedEvent());

    expect(serviceWithoutHistory.getNotificationCount()).toBeGreaterThanOrEqual(1);
  });

  it('should capture subject in log entries', async () => {
    await eventBus.emit(makeOrderCreatedEvent());

    const logs = historyService.query();
    expect(logs[0]?.subject).toContain('Order Confirmation');
  });
});

